bash -lc "source /ctf-workspace/venv/bin/activate && python - <<'PY'
from kazoo.client import KazooClient
import gzip

zk = KazooClient(hosts='192.168.5.6:2181')
zk.start()
paths = [
    '/druid/announcements/localhost:8083',
    '/druid/internal-discovery/ROUTER/localhost:8888',
    '/druid/internal-discovery/BROKER/localhost:8082'
]
for path in paths:
    try:
        data, _ = zk.get(path)
    except Exception as e:
        print('failed', path, e)
        continue
    if data.startswith(b'\x1f\x8b'):
        try:
            print('PATH', path)
            print(gzip.decompress(data).decode('utf-8', 'ignore'))
        except Exception as e:
            print('gzip error', path, e)
    else:
        print('PATH', path, 'DATA', data)
zk.stop()
PY"

